CREATE PROC [dbo].[CREATE_B2CS] @FromDate datetime,@ToDate datetime AS DECLARE @GSTIN AS CHAR(16) DECLARE @HSNCODETablename AS CHAR(16) DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) DECLARE @CompStateName As VarChar(50) SET @HSNCODETablename='##HSNCODETABLE' IF OBJECT_ID('tempdb..' + @HSNCODETablename) IS NOT NULL EXEC ('DROP TABLE ' + @HSNCODETablename) IF OBJECT_ID('dbo.B2CS','U') IS NOT NULL DROP TABLE B2CS IF OBJECT_ID('dbo.B2CS_Info','U') IS NOT NULL DROP TABLE B2CS_Info IF OBJECT_ID('dbo.B2CS_Inter','U') IS NOT NULL DROP TABLE B2CS_Inter SELECT @CompStateName=txt FROM SysParam Where paramCode='StateName' SELECT @HSNCodeField=Txt FROM SysParam WHERE ParamCode='AnalysisCodeUsedToStoreHSNCode' SET @IMTableQry= 'SELECT StockNo,'+ @HSNCodeField +' AS HSNCODE INTO ' + @HSNCODETablename + ' FROM ItemMaster' EXEC (@IMTableQry) SELECT @GSTIN=Txt FROM SysParam WHERE ParamCode='LocalSTaxRegnNo' SELECT * INTO B2CS_Inter FROM (SELECT  'OE' AS 'Type', Case when (STD.CustTaxType = '0' or STD.CustTaxType = 'NA')  then Cast(left(@GSTIN,2) as varchar(64)) else cast(left(Cust.LSTNo,2) as Varchar(64)) end As 'Place Of Supply', Cast((STD.stdTaxComp1Per + stdTaxComp2Per)  As Decimal(10,2)) AS 'Rate', Cast(Sum(Taxav1) as Decimal(10,2)) AS 'Taxable Value', CAST(CASE WHEN (STD.CustTaxType <> '0' and  STD.CustTaxType <> 'NA') THEN sum(STD.TaxComp2) ELSE sum(STD.TaxComp3) END AS Decimal(10,2))  AS 'CESS Amount', '' AS 'E-Commerce GSTIN' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.TrnType=STH.TrnType AND STD.TrnCtrlno=STH.TrnCtrlno INNER JOIN Customers Cust ON STH.PartyID = Cust.code WHERE STH.TrnType IN (2100) AND STD.DocDt>=@FromDate AND STD.DocDt<=@Todate AND STD.DocDt >= (SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND (STD.CustTaxType <> '1' or STH.NetDocValue <=250000) AnD len(isnull(Cust.LSTNO,'')) < 15 AND STD.docentvoidind = 0 Group by cast(left(Cust.LSTNo,2) as Varchar(64)), STD.CustTaxType, Case when STD.CustTaxType = '0' then Cast(left(@GSTIN,2) as varchar(64)) else cast(left(Cust.LSTNo,2) as Varchar(64)) end, STD.stdTaxComp1Per + stdTaxComp2Per, CAST(CASE WHEN STD.CustTaxType <> '0' THEN STD.TaxComp2 ELSE STD.TaxComp3 END AS Decimal(10,2)) UNION ALL SELECT 'OE' AS 'Type', Cast(left(@GSTIN,2) as varchar(64)) As 'Place Of Supply', Cast((STD.stdTaxComp1Per + stdTaxComp2Per)  As Decimal(10,2)) AS 'Rate', Cast(Sum(Taxav1) as Decimal(10,2)) AS 'Taxable Value', CAST(STD.TaxComp3 AS Decimal(10,2))  AS 'CESS Amount', '' AS 'E-Commerce GSTIN' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType WHERE STH.TrnType IN(2100) AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=(SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND ISNULL(STH.PartyId,'')='' AND STD.docentvoidind = 0 GROUP BY STD.CustTaxType, STD.stdTaxComp1Per + stdTaxComp2Per, STD.TaxComp3 Union ALL SELECT 'OE' AS 'Type', Case when (STD.CustTaxType = '0' or STD.CustTaxType = 'NA')  then Cast(left(@GSTIN,2) as varchar(64)) else cast(left(Cust.LSTNo,2) as Varchar(64)) end As 'Place Of Supply', Cast((STD.stdTaxComp1Per + stdTaxComp2Per)  As Decimal(10,2)) AS 'Rate', Cast(Sum(Taxav1)*-1 as Decimal(10,2)) AS 'Taxable Value', CAST(CASE WHEN (STD.CustTaxType <> '0' and  STD.CustTaxType <> 'NA') THEN sum(STD.TaxComp2) ELSE sum(STD.TaxComp3) END AS Decimal(10,2))  AS 'CESS Amount', '' AS 'E-Commerce GSTIN' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.TrnType=STH.TrnType AND STD.TrnCtrlno=STH.TrnCtrlno INNER JOIN Customers Cust ON STH.PartyID = Cust.code WHERE STH.TrnType IN (1300) AND STD.DocDt>=@FromDate AND STD.DocDt<=@Todate AND STD.DocDt >= (SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND (STD.CustTaxType <> '1' or STH.NetDocValue <=250000) AnD len(isnull(Cust.LSTNO,'')) < 15 AND STD.docentvoidind = 0 Group by cast(left(Cust.LSTNo,2) as Varchar(64)), STD.CustTaxType, Case when STD.CustTaxType = '0' then Cast(left(@GSTIN,2) as varchar(64)) else cast(left(Cust.LSTNo,2) as Varchar(64)) end, STD.stdTaxComp1Per + stdTaxComp2Per, CAST(CASE WHEN STD.CustTaxType <> '0' THEN STD.TaxComp2 ELSE STD.TaxComp3 END AS Decimal(10,2)) UNION ALL SELECT 'OE' AS 'Type', Cast(left(@GSTIN,2) as varchar(64)) As 'Place Of Supply', Cast((STD.stdTaxComp1Per + stdTaxComp2Per)  As Decimal(10,2)) AS 'Rate', Cast(Sum(Taxav1) * -1 as Decimal(10,2)) AS 'Taxable Value', CAST(STD.TaxComp3 AS Decimal(10,2))  AS 'CESS Amount', '' AS 'E-Commerce GSTIN' FROM  StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType WHERE STH.TrnType IN(1300) AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=(SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND ISNULL(STH.PartyId,'')='' AND STD.docentvoidind = 0 GROUP BY STD.CustTaxType, STD.stdTaxComp1Per + stdTaxComp2Per, STD.TaxComp3 ) As TEmp1 UPDATE  CD set [Place of Supply] = Cast([Place of Supply] as Varchar(4)) + '-' + GL.Descr FROM B2CS_Inter CD Inner JOIN (SELECT Code,DEscr FROM GenLookUp WHERE RecID=92 ) GL on CD.[Place of Supply] = GL.Code SELECT [Type], [Place Of Supply], [Rate], SUM([Taxable Value]) AS [Taxable Value], SUM([CESS Amount]) AS [CESS Amount], [E-Commerce GSTIN] INTO B2CS FROM B2CS_inter GROUP BY [Type], [Place Of Supply], [Rate], [E-Commerce GSTIN] SELECT SUM([Taxable Value]) AS [Total Taxable value],SUM([CESS AMOUNT]) AS [Total Cess] INTO B2CS_Info FROM B2CS IF OBJECT_ID('dbo.B2CSHeader','U') IS NOT NULL DROP TABLE B2CSHeader CREATE TABLE B2CSHeader ([Summary For B2CS(7)] Char(1)) INSERT INTO InfoTable Values('B2CS',2,'<<Default>>','B2CS',3) 